'use strict';

const passportUtils = require('../passport/utils');

module.exports = {
  getTenantFromToken,
};

function getTenantFromToken(req, tokenDecoded, credentials) {
  const tenantFromUrl = passportUtils.getUrlTenant(req);
  const tenantFromEnv = credentials && credentials.identityzone;
  let tenant = tenantFromUrl || tenantFromEnv;
  if (req.headers['x-subscriber-tenant']) {
    tenant = req.headers['x-subscriber-tenant'];
  } else if (tokenDecoded && tokenDecoded.ext_attr && tokenDecoded.ext_attr.zdn) {
    tenant = tokenDecoded.ext_attr.zdn;
  } else if (req.iasSubdomain) {
    tenant = req.iasSubdomain;
  }
  return tenant;
}
